import{_ as o,o as t,c as i,ag as r}from"./chunks/framework.DfsMvb5-.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),a={name:"changelog.md"};function n(l,e,s,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_0-2-1-2026-04-16" tabindex="-1">[0.2.1] - 2026-04-16 <a class="header-anchor" href="#_0-2-1-2026-04-16" aria-label="Permalink to &quot;[0.2.1] - 2026-04-16&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Persistent Preferences</strong>: <code>stableVolume</code>, <code>ambientMode</code>, and <code>hdr</code> toggles now persist via OPFS alongside <code>volume</code>, <code>muted</code>, and <code>playbackRate</code>. User toggles win over HTML attribute defaults on subsequent loads.</li><li><strong>Split-Source Volume Control</strong>: Volume button now visible when a separate native audio element is loaded, even if the video file has no muxed audio track.</li><li><strong>Smart Title Extraction</strong>: VLC-style filename cleaning strips release tags, codecs, and quality markers from tab titles. <code>Content-Disposition</code> filename used when the server provides one.</li><li><strong>Chrome Extension</strong>: Local file playback via popup file picker, drag-and-drop onto the player page, and a redesigned popup layout.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Context Menu</strong>: Slide-panel variant now only used on touch devices (<code>pointer: coarse</code>); narrow desktop windows get the regular hover-driven menu.</li><li><strong>Context Menu Scrolling</strong>: Max-height clamped to player height with subtle scrollbar styling so tall menus stay accessible on short players.</li><li><strong>Theme Color Cascade</strong>: <code>themecolor</code> attribute now flows to <code>--movi-primary-light</code> and <code>--movi-primary-dark</code> via <code>color-mix</code>, so active menu items and highlights follow the custom theme.</li><li><strong><code>title</code> Attribute</strong>: No longer triggers the browser&#39;s native tooltip on hover — title is rendered only by the in-player overlay.</li><li><strong>Subtitle/Audio Track Menus</strong>: Show language codes alongside track labels for clarity.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Short Video Stutter</strong>: Prebuffer media before <code>ready</code> so <code>play()</code> doesn&#39;t immediately stall on short clips.</li><li><strong>Background Audio at 50/60 fps</strong>: Skip video decode while hidden so audio keeps flowing on high-fps content.</li><li><strong>Narrow Viewport Controls</strong>: Buttons, gaps, and center play button tightened on viewports ≤ 480px to prevent the controls bar from overflowing the player box on iPhone 12 Pro-class widths.</li><li><strong>Empty State Placement</strong>: &quot;No Video&quot; placeholder no longer clips into the controls bar on short/narrow players.</li><li><strong>OSD Speed Icon</strong>: Correct speed icon shown when playback rate changes via hotkeys/context menu.</li></ul><h2 id="_0-2-0-2026-04-09" tabindex="-1">[0.2.0] - 2026-04-09 <a class="header-anchor" href="#_0-2-0-2026-04-09" aria-label="Permalink to &quot;[0.2.0] - 2026-04-09&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Ambient Mode</strong>: Dynamic letterbox glow that samples video colors in real-time. Smooth 60fps color transitions via WebGL clearColor. Toggle with <code>G</code> key or context menu. Works in fullscreen (letterbox) and normal mode (external wrapper). <code>ambientmode</code> attribute.</li><li><strong>Split Source Support</strong>: Separate video, audio, and subtitle file URLs via <code>videosrc</code>, <code>audiosrc</code>, <code>subtitlesrc</code> attributes.</li><li><strong>PGS Image Subtitles</strong>: Bitmap subtitle decoding with zlib decompression support.</li><li><strong>Network Disconnect Recovery</strong>: Intelligent CORS vs transient network failure detection (3-strike threshold). Online-event-aware backoff for instant retry on reconnection. Auto re-seek on recovery. 30s timeout on offline wait.</li><li><strong>Document Picture-in-Picture</strong>: Floating video window with play/pause, seek, mute, progress bar, time display, keyboard shortcuts, and back-to-tab button. Portrait video sizing. Rotation save/restore on PiP enter/exit.</li><li><strong>DRM Support</strong>: <code>drm</code> and <code>licenseurl</code> attributes for HLS streams with Widevine/FairPlay via EME API.</li><li><strong>HLS Quality Menu</strong>: Duplicate resolutions show bitrate (e.g., &quot;1080p · 5000 kbps&quot;).</li><li><strong>HLS Nerd Stats</strong>: Video codec, resolution, quality, frame rate, bitrate, buffer, HLS level, bandwidth, live latency, frames decoded/dropped.</li><li><strong>VLC-style Shortcuts</strong>: <code>V</code> subtitles, <code>B</code> audio, <code>+/-</code> speed, <code>L</code> loop, <code>U</code> stable volume, <code>H</code> HDR, <code>P</code> PiP, <code>G</code> ambient, <code>A</code> aspect ratio.</li><li><strong>Aspect Ratio Controls</strong>: <code>A</code> key cycles contain/cover/fill/zoom. Sub-menu with icons in context menu and bottom controls.</li><li><strong>Stable Volume</strong>: DynamicsCompressorNode for loudness normalization. Opt-in via <code>stablevolume</code> attribute.</li><li><strong>Nerd Stats</strong>: Press <code>I</code> for codec, resolution, FPS, decoder type, buffer health, color info, and live network/disk activity graph.</li><li><strong>Timeline</strong>: Press <code>T</code> for auto-generated thumbnail strip with chapter support. Arrow key navigation, click-to-seek.</li><li><strong>Chapter Support</strong>: Extract chapters from video metadata. Chapter markers on progress bar, chapter titles in seek tooltip.</li><li><strong>Video Rotation</strong>: Press <code>R</code> to rotate 90°. Metadata rotation auto-applied. Disabled during PiP.</li><li><strong>Keyboard Shortcuts Panel</strong>: Press <code>?</code> to view all shortcuts.</li><li><strong>Resume Playback</strong>: <code>resume</code> attribute saves position to localStorage with resume/start-over dialog.</li><li><strong>Encrypted Playback</strong>: AES-256-GCM chunked encryption with HMAC-SHA256 signed requests.</li><li><strong>Background Audio</strong>: Video keeps playing audio when tab is in background via Web Worker timer fallback.</li><li><strong>Chrome Extension</strong>: Popup with &quot;Paste &amp; Play&quot; and &quot;Play from Computer&quot;, context menu on video links, play button overlay on detected URLs.</li><li><strong>Privacy Policy</strong>: Published at docs site for Chrome Web Store compliance.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Buffering state now stops presentation loop so frames accumulate for reliable recovery.</li><li>Buffering exit requires video frames ready (with 3s fallback for async decoder delays).</li><li>Pause during buffering allowed from all UI controls (click, keyboard, buttons, PiP, context menu).</li><li><code>buffering → ended</code> state transition allowed for EOF during rebuffer.</li><li>Invalid packet size at EOF treated as EOF (not fatal error) for FFmpeg stale buffer data.</li><li>HDR icon changed to text badge style in OSD and context menu (matches bottom controls).</li><li>Extension description rewritten to remove excessive format keywords (Chrome Web Store compliance).</li><li>Console logs dropped in production build.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Hardware decoder error recovery with keyframe cache and software fallback.</li><li>Seek and play/pause during buffering state.</li><li>Network disconnect causing permanent CORS misclassification when <code>navigator.onLine</code> lags.</li><li>Stale stream loops from leaked online event listeners during backoff.</li><li>Multiple concurrent fetch loops after network recovery.</li><li>Clock advancing during buffering (presentation loop consuming frames).</li><li>PiP rotation clipping — rotation reset on PiP enter, restored on close.</li><li>PiP portrait video oversized — height-limited sizing for portrait aspect ratios.</li><li>Pause-seek loading stuck — <code>VideoDecoder.flush()</code> 1s timeout with reset+reconfigure fallback.</li><li>EOF not triggering — relaxed condition with 0.5s tolerance.</li><li>PiP canvas restore using <code>shadowRoot</code> directly.</li><li>PiP frame freeze on tab switch with <code>isPiPActive</code> guard.</li><li>EncryptedHttpSource network resilience matching HttpSource.</li><li>Nerd stats graph fullscreen positioning and CSS specificity.</li></ul><h2 id="_0-1-5-2026-02-15" tabindex="-1">[0.1.5] - 2026-02-15 <a class="header-anchor" href="#_0-1-5-2026-02-15" aria-label="Permalink to &quot;[0.1.5] - 2026-02-15&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Pitch preservation for playback rate changes</li><li>Pitch preservation support for HLS playback</li><li>MediaSession API integration for background playback and media controls</li><li>HTTPS support for local development environment</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Simplified error messages to be more concise and consistent</li><li>Replaced all hardcoded purple colors with CSS variables (--movi-primary) for full theme customization</li><li>Enhanced center play button with theme color by default</li><li>Updated loading spinner with responsive sizing and theme-aware colors</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Improved playback stability with enhanced error handling and timeout management</li><li>Resolved audio-video sync issues with hardware decoding</li><li>Distinguished 403/401/404 errors from CORS errors for better error reporting</li><li>CORS errors now propagate immediately instead of waiting for timeout</li><li>Title bar z-index now properly positioned below control menus in mobile view</li><li>Center play button backdrop blur now enabled on mobile/touch devices</li><li>Controls no longer auto-hide when menus are open on mobile</li></ul><h2 id="_0-1-4-2026-02-11" tabindex="-1">[0.1.4] - 2026-02-11 <a class="header-anchor" href="#_0-1-4-2026-02-11" aria-label="Permalink to &quot;[0.1.4] - 2026-02-11&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Resolved video stalling during playback and improved A/V sync</li><li>Playback speed changes now take immediate effect on audio</li><li>Auto-unmute when volume slider is moved while muted</li><li>Mute button now correctly toggles audio muting</li></ul><h2 id="previous-versions" tabindex="-1">Previous Versions <a class="header-anchor" href="#previous-versions" aria-label="Permalink to &quot;Previous Versions&quot;">​</a></h2><p>See git commit history for changes in versions prior to 0.1.4.</p>',29)])])}const p=o(a,[["render",n]]);export{g as __pageData,p as default};
